import{_ as s,o as n,c as l,a4 as t}from"./chunks/framework._in6GHBg.js";const d=JSON.parse('{"title":"概率与统计详解","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Learn-Detail-007-概率与统计详解-V1.0-20260405.md","filePath":"math/Math-Learn-Detail-007-概率与统计详解-V1.0-20260405.md"}'),i={name:"math/Math-Learn-Detail-007-概率与统计详解-V1.0-20260405.md"};function e(p,a,o,r,h,c){return n(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="概率与统计详解" tabindex="-1">概率与统计详解 <a class="header-anchor" href="#概率与统计详解" aria-label="Permalink to &quot;概率与统计详解&quot;">​</a></h1><p><strong>从&quot;可能性&quot;到&quot;数据驱动的决策&quot;</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>掌握计数原理和排列组合</li><li>理解概率的本质和计算方法</li><li>能用统计方法从数据中提取信息</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>概率与统计</span></span>
<span class="line"><span>├── 计数原理</span></span>
<span class="line"><span>│   ├── 分类加法原理</span></span>
<span class="line"><span>│   ├── 分步乘法原理</span></span>
<span class="line"><span>│   ├── 排列 ⭐</span></span>
<span class="line"><span>│   └── 组合 ⭐</span></span>
<span class="line"><span>├── 概率</span></span>
<span class="line"><span>│   ├── 随机事件与概率</span></span>
<span class="line"><span>│   ├── 古典概型 ⭐</span></span>
<span class="line"><span>│   ├── 条件概率</span></span>
<span class="line"><span>│   ├── 独立事件</span></span>
<span class="line"><span>│   └── 随机变量与分布列 ⭐</span></span>
<span class="line"><span>└── 统计</span></span>
<span class="line"><span>    ├── 抽样方法</span></span>
<span class="line"><span>    ├── 用样本估计总体</span></span>
<span class="line"><span>    └── 统计案例 ⭐</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：集合、函数</li><li><strong>后续应用</strong>：大学概率论、数理统计、机器学习</li><li><strong>跨学科联系</strong>：金融（风险评估）、医学（临床试验）、人工智能（贝叶斯推断）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-计数原理" tabindex="-1">2.1 计数原理 <a class="header-anchor" href="#_2-1-计数原理" aria-label="Permalink to &quot;2.1 计数原理&quot;">​</a></h3><p><strong>分类加法原理</strong>：</p><ul><li>完成一件事有n类方法，每类有mᵢ种方法</li><li>则总方法数 = m₁ + m₂ + ... + mₙ</li><li><strong>关键</strong>：各类方法<strong>相互独立</strong>，任选一类即可完成</li></ul><p><strong>分步乘法原理</strong>：</p><ul><li>完成一件事需n个步骤，每步有mᵢ种方法</li><li>则总方法数 = m₁ × m₂ × ... × mₙ</li><li><strong>关键</strong>：各步骤<strong>依次进行</strong>，缺一不可</li></ul><hr><h3 id="_2-2-排列与组合-⭐" tabindex="-1">2.2 排列与组合 ⭐ <a class="header-anchor" href="#_2-2-排列与组合-⭐" aria-label="Permalink to &quot;2.2 排列与组合 ⭐&quot;">​</a></h3><p><strong>排列</strong>（有序）：</p><ul><li>从n个不同元素中取m个排成一列</li><li>A(n,m) = n!/(n-m)! = n(n-1)...(n-m+1)</li></ul><p><strong>组合</strong>（无序）：</p><ul><li>从n个不同元素中取m个并成一组</li><li>C(n,m) = A(n,m)/m! = n!/[m!(n-m)!]</li></ul><p><strong>组合性质</strong>：</p><ul><li>C(n,m) = C(n,n-m)</li><li>C(n,m) = C(n-1,m-1) + C(n-1,m)（帕斯卡公式）</li></ul><p><strong>区分排列与组合</strong>：</p><ul><li>交换顺序是否算不同情况？</li><li>是→排列，否→组合</li></ul><hr><h3 id="_2-3-二项式定理" tabindex="-1">2.3 二项式定理 <a class="header-anchor" href="#_2-3-二项式定理" aria-label="Permalink to &quot;2.3 二项式定理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(a+b)ⁿ = C(n,0)aⁿ + C(n,1)a^(n-1)b + ... + C(n,k)a^(n-k)b^k + ... + C(n,n)bⁿ</span></span></code></pre></div><p><strong>通项公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T_(k+1) = C(n,k) · a^(n-k) · b^k</span></span></code></pre></div><p><strong>应用</strong>：</p><ul><li>求展开式中某一项的系数</li><li>赋值法求系数和（令a=b=1得所有系数和为2ⁿ）</li></ul><hr><h3 id="_2-4-概率基础" tabindex="-1">2.4 概率基础 <a class="header-anchor" href="#_2-4-概率基础" aria-label="Permalink to &quot;2.4 概率基础&quot;">​</a></h3><p><strong>古典概型</strong> ⭐：</p><ul><li>有限个等可能结果</li><li>P(A) = A包含的基本事件数 / 总基本事件数</li></ul><p><strong>概率性质</strong>：</p><ul><li>0 ≤ P(A) ≤ 1</li><li>P(必然事件) = 1，P(不可能事件) = 0</li><li>P(A∪B) = P(A) + P(B) - P(A∩B)</li><li>若A,B互斥，则P(A∪B) = P(A) + P(B)</li></ul><p><strong>对立事件</strong>：</p><ul><li>P(A) + P(Ā) = 1</li><li>当直接求P(A)困难时，可求P(Ā) = 1 - P(Ā)</li></ul><hr><h3 id="_2-5-条件概率与独立事件" tabindex="-1">2.5 条件概率与独立事件 <a class="header-anchor" href="#_2-5-条件概率与独立事件" aria-label="Permalink to &quot;2.5 条件概率与独立事件&quot;">​</a></h3><p><strong>条件概率</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(B|A) = P(A∩B) / P(A)  （P(A)&gt;0）</span></span></code></pre></div><ul><li>含义：在A发生的条件下，B发生的概率</li></ul><p><strong>乘法公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(A∩B) = P(A) · P(B|A)</span></span></code></pre></div><p><strong>独立事件</strong>：</p><ul><li>A,B独立 ⇔ P(A∩B) = P(A) · P(B)</li><li>独立时：P(B|A) = P(B)</li></ul><p><strong>判断独立的方法</strong>：</p><ul><li>一个事件发生与否不影响另一个事件的概率</li></ul><hr><h3 id="_2-6-随机变量与分布列-⭐" tabindex="-1">2.6 随机变量与分布列 ⭐ <a class="header-anchor" href="#_2-6-随机变量与分布列-⭐" aria-label="Permalink to &quot;2.6 随机变量与分布列 ⭐&quot;">​</a></h3><p><strong>离散型随机变量</strong>：取值可一一列举的随机变量X</p><p><strong>分布列</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">X</th><th style="text-align:center;">x₁</th><th style="text-align:center;">x₂</th><th style="text-align:center;">...</th><th style="text-align:center;">xₙ</th></tr></thead><tbody><tr><td style="text-align:center;">P</td><td style="text-align:center;">p₁</td><td style="text-align:center;">p₂</td><td style="text-align:center;">...</td><td style="text-align:center;">pₙ</td></tr></tbody></table><p><strong>性质</strong>：</p><ul><li>pᵢ ≥ 0</li><li>Σpᵢ = 1</li></ul><p><strong>期望（均值）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E(X) = x₁p₁ + x₂p₂ + ... + xₙpₙ</span></span></code></pre></div><ul><li>反映随机变量取值的&quot;平均水平&quot;</li></ul><p><strong>方差</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D(X) = E(X²) - [E(X)]² = Σ(xᵢ-E(X))²pᵢ</span></span></code></pre></div><ul><li>反映随机变量取值的&quot;离散程度&quot;</li></ul><p><strong>常见分布</strong>：</p><ul><li><strong>二点分布</strong>（0-1分布）：X~B(1,p)</li><li><strong>二项分布</strong>：X~B(n,p)，P(X=k)=C(n,k)p^k(1-p)^(n-k)</li><li><strong>超几何分布</strong>：不放回抽样的概率分布</li></ul><hr><h3 id="_2-7-统计" tabindex="-1">2.7 统计 <a class="header-anchor" href="#_2-7-统计" aria-label="Permalink to &quot;2.7 统计&quot;">​</a></h3><p><strong>抽样方法</strong>：</p><ul><li><strong>简单随机抽样</strong>：抽签法、随机数法</li><li><strong>系统抽样</strong>：等间隔抽样</li><li><strong>分层抽样</strong>：按特征分层，每层按比例抽样</li></ul><p><strong>用样本估计总体</strong>：</p><ul><li><strong>频率分布直方图</strong>：横轴为数据分组，纵轴为频率/组距</li><li><strong>数字特征</strong>： <ul><li>平均数：x̄ = (x₁+x₂+...+xₙ)/n</li><li>方差：s² = Σ(xᵢ-x̄)²/n</li><li>标准差：s = √s²</li></ul></li></ul><p><strong>统计案例</strong> ⭐：</p><ul><li>回归分析：线性回归方程 ŷ = bx + a</li><li>独立性检验：2×2列联表的卡方检验</li></ul><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-排列组合计数" tabindex="-1">例题1：排列组合计数 <a class="header-anchor" href="#例题1-排列组合计数" aria-label="Permalink to &quot;例题1：排列组合计数&quot;">​</a></h3><p><strong>题目</strong>：从5名男生和4名女生中选3人，要求至少有1名女生，有多少种选法？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>法1：直接法</span></span>
<span class="line"><span>1女2男：C(4,1)·C(5,2) = 4×10 = 40</span></span>
<span class="line"><span>2女1男：C(4,2)·C(5,1) = 6×5 = 30</span></span>
<span class="line"><span>3女0男：C(4,3) = 4</span></span>
<span class="line"><span>共：40+30+4 = 74</span></span>
<span class="line"><span></span></span>
<span class="line"><span>法2：间接法（推荐）</span></span>
<span class="line"><span>总数：C(9,3) = 84</span></span>
<span class="line"><span>不满足（全男生）：C(5,3) = 10</span></span>
<span class="line"><span>∴ 84-10 = 74</span></span></code></pre></div><hr><h3 id="例题2-古典概型" tabindex="-1">例题2：古典概型 <a class="header-anchor" href="#例题2-古典概型" aria-label="Permalink to &quot;例题2：古典概型&quot;">​</a></h3><p><strong>题目</strong>：掷两枚骰子，点数之和为7的概率是多少？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总基本事件数：6×6 = 36</span></span>
<span class="line"><span></span></span>
<span class="line"><span>和为7的情况：</span></span>
<span class="line"><span>(1,6), (2,5), (3,4), (4,3), (5,2), (6,1) → 6种</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P = 6/36 = 1/6</span></span></code></pre></div><hr><h3 id="例题3-条件概率" tabindex="-1">例题3：条件概率 <a class="header-anchor" href="#例题3-条件概率" aria-label="Permalink to &quot;例题3：条件概率&quot;">​</a></h3><p><strong>题目</strong>：某班有30名男生，20名女生。男生中有10人会游泳，女生中有5人会游泳。现随机选一人，已知选中的是男生，求他会游泳的概率。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设A=&quot;选中男生&quot;，B=&quot;会游泳&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P(B|A) = 男生中会游泳的人数 / 男生总人数</span></span>
<span class="line"><span>        = 10/30</span></span>
<span class="line"><span>        = 1/3</span></span></code></pre></div><hr><h3 id="例题4-分布列与期望" tabindex="-1">例题4：分布列与期望 <a class="header-anchor" href="#例题4-分布列与期望" aria-label="Permalink to &quot;例题4：分布列与期望&quot;">​</a></h3><p><strong>题目</strong>：掷一枚均匀骰子，X表示出现的点数，求X的分布列和期望。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分布列：</span></span>
<span class="line"><span>| X | 1 | 2 | 3 | 4 | 5 | 6 |</span></span>
<span class="line"><span>|---|---|---|---|---|---|---|</span></span>
<span class="line"><span>| P |1/6|1/6|1/6|1/6|1/6|1/6|</span></span>
<span class="line"><span></span></span>
<span class="line"><span>E(X) = 1×(1/6) + 2×(1/6) + ... + 6×(1/6)</span></span>
<span class="line"><span>     = (1+2+3+4+5+6)/6</span></span>
<span class="line"><span>     = 21/6 = 3.5</span></span></code></pre></div><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：从1,2,3,4,5中任取3个数，能组成多少个不同的三位数？</p><p><strong>练习2</strong>：6个人排成一排，甲乙必须相邻，有多少种排法？</p><p><strong>练习3</strong>：袋中有3红球2白球，任取2球，求取到1红1白的概率。</p><p><strong>练习4</strong>：已知P(A)=0.6，P(B)=0.5，P(A∩B)=0.3，求P(A∪B)。</p><p><strong>参考答案</strong>：</p><ul><li>练习1：A(5,3) = 60</li><li>练习2：A(2,2)·A(5,5) = 2×120 = 240（捆绑法）</li><li>练习3：C(3,1)·C(2,1)/C(5,2) = 6/10 = 3/5</li><li>练习4：P(A∪B) = 0.6+0.5-0.3 = 0.8</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习5</strong>：求(2x-1)⁵展开式中x³的系数。</p><p><strong>练习6</strong>：某射手每次命中概率为0.8，独立射击3次，求命中次数X的分布列和期望。</p><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-排列组合分不清什么时候用a什么时候用c" tabindex="-1">FAQ 1：排列组合分不清什么时候用A什么时候用C <a class="header-anchor" href="#faq-1-排列组合分不清什么时候用a什么时候用c" aria-label="Permalink to &quot;FAQ 1：排列组合分不清什么时候用A什么时候用C&quot;">​</a></h3><p><strong>判断方法</strong>：</p><ul><li>把选出的元素<strong>交换顺序</strong>，看是否算不同情况</li><li>是→排列A，否→组合C</li></ul><p><strong>示例</strong>：</p><ul><li>选3人当班长、学习委员、体育委员→有序→A</li><li>选3人组成学习小组→无序→C</li></ul><hr><h3 id="faq-2-计数时总是重复或遗漏" tabindex="-1">FAQ 2：计数时总是重复或遗漏 <a class="header-anchor" href="#faq-2-计数时总是重复或遗漏" aria-label="Permalink to &quot;FAQ 2：计数时总是重复或遗漏&quot;">​</a></h3><p><strong>避免重复</strong>：</p><ul><li>分类时要<strong>不重不漏</strong></li><li>使用间接法（总数-不满足）往往更简单</li></ul><p><strong>避免遗漏</strong>：</p><ul><li>画树状图或列表枚举</li><li>先分类再分步</li></ul><hr><h3 id="faq-3-古典概型总算错基本事件数" tabindex="-1">FAQ 3：古典概型总算错基本事件数 <a class="header-anchor" href="#faq-3-古典概型总算错基本事件数" aria-label="Permalink to &quot;FAQ 3：古典概型总算错基本事件数&quot;">​</a></h3><p><strong>注意</strong>：</p><ul><li>是否等可能？</li><li>是否有序？（掷两枚骰子(1,2)和(2,1)是不同结果）</li></ul><p><strong>验证</strong>：</p><ul><li>所有基本事件概率之和为1</li><li>用简单情况验证公式</li></ul><hr><h3 id="faq-4-分布列的期望公式记不住" tabindex="-1">FAQ 4：分布列的期望公式记不住 <a class="header-anchor" href="#faq-4-分布列的期望公式记不住" aria-label="Permalink to &quot;FAQ 4：分布列的期望公式记不住&quot;">​</a></h3><p><strong>理解记忆</strong>：</p><ul><li>期望就是&quot;加权平均&quot;</li><li>每个取值×对应概率，再求和</li><li>类似计算平均分：各科成绩×学分，再除以总学分</li></ul><hr><h2 id="六、本章检查清单" tabindex="-1">六、本章检查清单 <a class="header-anchor" href="#六、本章检查清单" aria-label="Permalink to &quot;六、本章检查清单&quot;">​</a></h2><ul><li>[ ] 能区分分类加法和分步乘法</li><li>[ ] 能正确计算排列数A(n,m)和组合数C(n,m)</li><li>[ ] 能用二项式定理展开并求特定项系数</li><li>[ ] 能计算古典概型的概率</li><li>[ ] 理解条件概率和独立事件的概念</li><li>[ ] 能写出离散型随机变量的分布列</li><li>[ ] 能计算期望E(X)和方差D(X)</li><li>[ ] 了解三种抽样方法的区别</li></ul><hr><p><strong>文档编号</strong>: Math-Learn-Detail-007<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,139)])])}const u=s(i,[["render",e]]);export{d as __pageData,u as default};
